VALUES
  ('retired-7ec62a85-moex-00333', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '公務員甲對於其長官乙所發之職務命令，因其內容已構成洩密罪，即向乙報告。乙仍堅持命令內 容，甲遂依乙之命令為行為。關於甲應負之責任，下列敘述何者正確？', '["甲對於違法之命令已盡報告之義務，故不負行政責任", "甲對於違法之命令已盡報告之義務，但明知該命令已構成犯罪，故仍應負刑事責任", "甲如要求乙以書面署名下達，遭乙拒絕，則不負行政責任", "甲如要求乙以書面署名下達，乙亦為之，則不負刑事責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00334', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於行政機關裁量權之行使，下列敘述何者正確？', '["行政機關行使裁量權，係屬行政之自由性，行政法院僅得為適當性審查", "法律授予行政裁量權之目的，旨在追求個案正義，行政機關不得訂定一般性之裁量基準", "行政裁量係行政機關本於專業之判斷，法院應尊重行政機關之決定", "行政裁量違反法令授權之目的或逾越授權之範圍者，構成裁量瑕疵之違法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00335', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '有關私經濟行政之敘述，下列何者錯誤？', '["受私法所支配", "強調私法自治，不受憲法原則拘束", "可作為國家達成行政任務之手段", "應循民事紛爭解決機制救濟之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00336', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '下列何者非屬我國現行法之公法人？', '["國家中山科學研究院", "國家通訊傳播委員會", "國家運動訓練中心", "國家表演藝術中心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00337', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '有關行政機關管轄權之敘述，下列何者正確？', '["數行政機關間對於同一事件均認為有管轄權時，應先交由司法機關認定解決之", "委任係指無隸屬關係機關間管轄權之變動", "委託係指有隸屬關係機關間管轄權之變動", "職務協助係指向無隸屬關係之其他機關請求協助"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00338', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於公務員之兼職行為，下列敘述何者正確？', '["離職後2年，得擔任與其離職前之職務直接相關之營利事業董事", "經服務機關或上級機關許可後，得有條件兼任國立大學講師", "經服務機關或上級機關許可後，得兼任營利事業董事及獨立董事", "擔任公益財團法人之董事，不需經服務機關或上級機關許可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00339', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於公務人員保障法復審規定之敘述，下列何者正確？', '["非現職之公務人員不得提起復審", "上級機關本於法定職權所為行政處分，交由下級機關執行者，以該下級機關為原處分機關", "復審人經由原處分機關向公務人員保障暨培訓委員會提起復審", "公務人員之遺族不得提起復審"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
