  ('retired-7ec62a85-moex-00341', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '公務人員考績法關於考績評定之原則，下列敘述何者錯誤？', '["專案考績不得與平時考核功過相抵銷", "除功過互相抵銷外，曾記一大過人員，考績不得列乙等以上", "平時成績紀錄及獎懲，應為考績評定分數之重要依據", "除機關首長外，僅以同職等人員為考績之比較範圍 13730"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00342', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '依行政程序法之規定，法規命令之訂定應經其他機關核准，而未經核准即發布者，其效力為何？', '["得撤銷", "既經發布，即無效力之瑕疵", "得廢止", "無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL)
